1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Step = QuoteStep;
15	type Customer = { yearsWithMHPCO: number };
16	type Scenario = { customer: Customer; steps: Step[] };
17	
18	type ItemTypeSpec = { basePremium: number; isComponent: boolean };
19	
20	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
21	  sword: { basePremium: 100, isComponent: false },
22	  amulet: { basePremium: 60, isComponent: false },
23	  staff: { basePremium: 80, isComponent: false },
24	  potion: { basePremium: 40, isComponent: false },
25	  rune: { basePremium: 25, isComponent: true },
26	  moonstone: { basePremium: 25, isComponent: true },
27	};
28	
29	const basePremiumFor = (item: Item): number => ITEM_TYPES[item.type].basePremium;
30	
31	const countByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const item of items) {
34	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
35	  }
36	  return counts;
37	};
38	
39	const premiumForTypeCount = (type: string, count: number): number => {
40	  const spec = ITEM_TYPES[type];
41	  return spec.isComponent && count === BLOCK_SIZE
42	    ? BLOCK_PREMIUM
43	    : count * spec.basePremium;
44	};
45	
46	const basePremiumOf = (items: Item[]): number => {
47	  let total = 0;
48	  for (const [type, count] of countByType(items)) {
49	    total += premiumForTypeCount(type, count);
50	  }
51	  return total;
52	};
53	
54	type SurchargeRule = { applies: (item: Item) => boolean; rate: number };
55	
56	const SURCHARGE_RULES: SurchargeRule[] = [
57	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
58	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
59	];
60	
61	const surchargeRateFor = (item: Item): number =>
62	  SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
63	
64	const itemSurchargesOf = (items: Item[]): number =>
65	  items.reduce((sum, item) => sum + basePremiumFor(item) * surchargeRateFor(item), 0);
66	
67	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
68	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
69	    ? basePremium * LOYALTY_DISCOUNT_RATE
70	    : 0;
71	
72	const quoteForStep = ({ items }: QuoteStep, customer: Customer, stepIndex: number) => {
73	  const basePremium = basePremiumOf(items);
74	  const itemSurcharges = itemSurchargesOf(items);
75	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
76	  const loyaltyDiscount = loyaltyDiscountFor(basePremium, customer);
77	  const followUpDiscount = stepIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
78	  return {
79	    premium: Math.ceil(
80	      basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
81	    ),
82	  };
83	};
84	
85	export const runScenario = (scenario: Scenario): unknown => {
86	  return { results: scenario.steps.map((step, i) => quoteForStep(step, scenario.customer, i)) };
87	};
